  setupSearch();
  setupHomeTabs();
  setupRankingsSort();
  setupRankingsSearch();
  setupGamesSearch();
  setupGuidesSearch();
  setupGuidesTabs();
  setupHeaderScroll();
  setupMobileMenu();
  setupHeaderSearchVisibility();
